export const STARTER_FOOD_CATALOG_VERSION = 2;

export function getCatalogFoodName(foodCode, language) {
  const entry = STARTER_FOOD_CATALOG.find((food) => food.foodCode === foodCode);

  if (!entry) {
    return null;
  }

  return entry.names[language] ?? entry.names.en;
}
